"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

type MessageRole = "user" | "assistant" | "system";

interface MessageContextValue {
  role: MessageRole;
}

interface MessageRootProps extends React.ComponentProps<"div"> {
  /** The role of the message sender */
  role?: MessageRole;
}

interface MessageAvatarProps extends React.ComponentProps<"div"> {
  /** Source URL for the avatar image */
  src?: string;
  /** Alt text for the avatar image */
  alt?: string;
  /** Fallback content when no image is provided */
  fallback?: React.ReactNode;
}

interface MessageContentProps extends React.ComponentProps<"div"> {}

interface MessageActionsProps extends React.ComponentProps<"div"> {}

// =============================================================================
// CONTEXT
// =============================================================================

const MessageContext = React.createContext<MessageContextValue>({
  role: "user",
});

function useMessageContext() {
  return React.useContext(MessageContext);
}

// =============================================================================
// VARIANTS
// =============================================================================

const messageRootVariants = cva("flex gap-3 w-full", {
  variants: {
    role: {
      user: "flex-row-reverse",
      assistant: "flex-row",
      system: "flex-row justify-center",
    },
  },
  defaultVariants: {
    role: "user",
  },
});

const messageContentVariants = cva(
  "rounded-2xl px-4 py-2.5 text-sm leading-relaxed max-w-[80%] whitespace-pre-wrap break-words",
  {
    variants: {
      role: {
        user: "bg-primary text-primary-foreground rounded-br-md",
        assistant:
          "bg-muted text-foreground border border-border/50 rounded-bl-md",
        system:
          "bg-muted/50 text-muted-foreground text-center text-xs italic max-w-[90%]",
      },
    },
    defaultVariants: {
      role: "user",
    },
  }
);

// =============================================================================
// COMPONENTS
// =============================================================================

function MessageRoot({
  role = "user",
  className,
  children,
  ...props
}: MessageRootProps) {
  const contextValue = React.useMemo(() => ({ role }), [role]);

  return (
    <MessageContext.Provider value={contextValue}>
      <div
        data-slot="message"
        data-role={role}
        className={cn(messageRootVariants({ role }), className)}
        {...props}
      >
        {children}
      </div>
    </MessageContext.Provider>
  );
}

function MessageAvatar({
  src,
  alt = "Avatar",
  fallback,
  className,
  ...props
}: MessageAvatarProps) {
  const { role } = useMessageContext();

  return (
    <div
      data-slot="message-avatar"
      className={cn(
        "shrink-0 w-8 h-8 rounded-full overflow-hidden",
        role === "system" && "hidden",
        className
      )}
      {...props}
    >
      {src ? (
        <img
          src={src}
          alt={alt}
          className="w-full h-full object-cover"
          loading="lazy"
        />
      ) : (
        <div className="w-full h-full flex items-center justify-center bg-muted text-muted-foreground text-xs font-medium">
          {fallback || (role === "assistant" ? "AI" : "U")}
        </div>
      )}
    </div>
  );
}

function MessageContent({
  className,
  children,
  ...props
}: MessageContentProps) {
  const { role } = useMessageContext();

  return (
    <div
      data-slot="message-content"
      className={cn(messageContentVariants({ role }), className)}
      {...props}
    >
      {children}
    </div>
  );
}

function MessageActions({
  className,
  children,
  ...props
}: MessageActionsProps) {
  const { role } = useMessageContext();

  return (
    <div
      data-slot="message-actions"
      className={cn(
        "flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity",
        role === "user" ? "self-end" : "self-start",
        className
      )}
      {...props}
    >
      {children}
    </div>
  );
}

// =============================================================================
// COMPOUND COMPONENT
// =============================================================================

MessageRoot.displayName = "Message";
MessageAvatar.displayName = "Message.Avatar";
MessageContent.displayName = "Message.Content";
MessageActions.displayName = "Message.Actions";

const Message = Object.assign(MessageRoot, {
  Avatar: MessageAvatar,
  Content: MessageContent,
  Actions: MessageActions,
});

export {
  Message,
  useMessageContext,
  messageRootVariants,
  messageContentVariants,
};
export type {
  MessageRole,
  MessageRootProps,
  MessageAvatarProps,
  MessageContentProps,
  MessageActionsProps,
};
